async (params, browser) => {
  // Open OpenSea search
  await browser.open(`https://opensea.io/search?query=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('a[data-id=\'Item\'], a[href*=\'/collection/\'], [class*=\'AssetCard\'], [class*=\'collection\']', 15000)

  // Let results render
  await browser.wait(2500)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('a[data-id="Item"], a[href*="/collection/"], [class*="AssetCard"], [class*="collection-card"]'); const seen = new Set(); for (let i = 0; i < items.length && results.length < 15; i++) { const el = items[i]; const link = el.href || el.querySelector('a')?.href || ''; if (!link || seen.has(link)) continue; seen.add(link); const nameEl = el.querySelector('[data-testid="ItemCardFooter-name"], [class*="name"], h3, span'); const priceEl = el.querySelector('[data-testid="ItemCardPrice"], [class*="price"], [class*="floor"]'); const imgEl = el.querySelector('img'); const name = nameEl?.textContent?.trim() || ''; if (!name) continue; results.push({ name: name, url: link, floor_price: priceEl?.textContent?.trim() || '', image: imgEl?.src || '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
